def main():
    """Main entry point."""
    import argparse

    parser = argparse.ArgumentParser(description="Redis Lua Script Executor")
    parser.add_argument("--host", default="localhost", help="Redis host (default: localhost)")
    parser.add_argument("--port", type=int, default=6379, help="Redis port (default: 6379)")
    parser.add_argument("--db", type=int, default=0, help="Redis database number (default: 0)")
    parser.add_argument("--password", default=None, help="Redis password")
    parser.add_argument("--mode", choices=["interactive", "demo"], default="interactive",
                        help="Run mode: interactive or demo (default: interactive)")
    parser.add_argument("--script", default=None, help="Execute a single Lua script and exit")
    parser.add_argument("--keys", default="", help="Comma-separated keys for --script mode")
    parser.add_argument("--args", default="", help="Comma-separated args for --script mode")

    args = parser.parse_args()

    try:
        client = RedisLuaClient(
            host=args.host,
            port=args.port,
            db=args.db,
            password=args.password
        )
    except redis.ConnectionError:
        sys.exit(1)

    try:
        if args.script:
            # Single script execution mode
            keys = [k.strip() for k in args.keys.split(",") if k.strip()]
            script_args = [a.strip() for a in args.args.split(",") if a.strip()]
            result = client.execute_lua_script(args.script, keys, script_args)
            print(f"{result}")
        elif args.mode == "demo":
            demo_mode(client)
        else:
            interactive_mode(client)
    finally:
        client.close()


if __name__ == "__main__":
    main()